if (!m) return null;
const ack = RED.util.cloneMessage(msg);
ack.payload = '';
ack.statusCode = '2.04';
const out = RED.util.cloneMessage(msg);
out.topic = `campus/b01/f${m[1]}/r${m[2]}/alert`;
out.payload = p;
out.qos = 2;
return [ack, out];
